#include &lt;stdio.h&gt;
#include &lt;sys/mman.h&gt;
#include &lt;unistd.h&gt;

void* allocate_raw_pages(size_t size) {
    // MAP_ANONYMOUS means "Not backed by a file, just give me raw RAM"
    // MAP_PRIVATE means "Only this process can see it"
    void *ptr = mmap(NULL, size, PROT_READ | PROT_WRITE, 
                     MAP_PRIVATE | MAP_ANONYMOUS, -1, 0);

    if (ptr == MAP_FAILED) {
        perror("mmap failed");
        return NULL;
    }
    return ptr;
}

int main() {
    // Allocate exactly one Hardware Page (usually 4096 bytes)
    size_t page_size = sysconf(_SC_PAGESIZE);

    char *memory = allocate_raw_pages(page_size);
    if (memory) {
        memory[0] = 'A';
        printf("Success. RAM allocated at: %p\n", (void*)memory);

        // You CANNOT use free() on mmap'd memory. You must unmap it.
        munmap(memory, page_size);
    }
    return 0;
}

